#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e6+5;
const LL INF = 0x3f3f3f3f3f3f3f3f;
LL n,a[N],q[N],Ans;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void solve(LL l,LL r,int L,int R){
    if(L>R||l>=r)return;
    LL mid=(l+r)>>1,sum=0;
    for(int i=L;i<=R;i++)sum+=abs(a[i]-mid-1);
    LL lst=sum,pmid=L-1;
    for(int i=L;i<=R;i++){
        sum-=abs(a[i]-mid-1);
        sum+=abs(a[i]-mid);
        if(sum<lst)lst=sum,pmid=i;
    }for(int i=L;i<=pmid;i++)q[i]=mid;
    for(int i=pmid+1;i<=R;i++)q[i]=mid+1;
    solve(l,mid,L,pmid);
    solve(mid+1,r,pmid+1,R);return;
}
int main(){
    n=read();
    for(int i=1;i<=n;i++)a[i]=read()-i;
    solve(-INF,INF,1,n);Ans=0;
    for(int i=1;i<=n;i++)Ans+=abs(a[i]-q[i]);
    cout<<Ans<<"\n";
    for(int i=1;i<=n;i++)cout<<q[i]+i<<"\n";
    return 0;
}
